() => {
  const btn = document.querySelector('button[aria-controls="cdk-menu-1"]');
  const menu = document.querySelector('#cdk-menu-1');
  if (!btn || !menu) return;

  const wrap = menu.closest('.cdk-overlay-connected-position-bounding-box');
  if (wrap) {
    wrap.style.cssText = 'position:fixed;left:0;top:0;width:100vw;height:100vh;display:block;transform:none;';
  }

  const pane = menu.closest('.cdk-overlay-pane');
  if (pane) {
    pane.style.cssText = 'position:fixed;transform:none;';
  }

  const br = btn.getBoundingClientRect();
  const mr = menu.getBoundingClientRect();
  const left = Math.round(br.right - mr.width);
  const top = Math.round(br.bottom + 4);

  const target = pane || menu;
  target.style.left = left + 'px';
  target.style.top = top + 'px';
}
